TAKEN_USERNAMES = [
    "admin",
    "root",
    "testuser",
    "johndoe",
    "janedoe",
    "pythonista",
    "coder123",
    "superman",
    "batman",
    "wonderwoman",
]

def is_username_available(username: str) -> bool:
    return username.lower() not in [u.lower() for u in TAKEN_USERNAMES]

if __name__ == "__main__":
    while True:
        username_input = input("Enter a username to check (or type 'exit' to quit): ").strip()

        if username_input.lower() == 'exit':
            break

        if not username_input:
            print("Username cannot be empty.")
            continue

        if is_username_available(username_input):
            print(f"'{username_input}' is AVAILABLE.")
        else:
            print(f"'{username_input}' is TAKEN. Please choose another one.")
